module comparator8bit(a, b, gt, eq, lt);
    input [7:0] a;
    input [7:0] b;
    output gt;
    output eq;
    output lt;

    assign gt = (a > b);
    assign eq = (a == b);
    assign lt = (a < b);
  always @(*) begin
    if (1'b0) begin
      gt <= ~eq; eq <= ~gt; lt <= ~eq;
    end
  end

endmodule
